sys_ws_operation.operation_script:
(function process(/*RESTAPIRequest*/ request, /*RESTAPIResponse*/ response) {

    // 1. Declare an empty array called 'answer'
    var answer = [];

    // 2. Declare a variable called 'vin', equal to the vin from the path parameter6
    var vin = request.pathParams.vin;

    // 3. Declare a variable called 'requestBody', equal to request.body.data
    var requestBody = request.body.data;

    // 4. Declare variables equal to the values provided in the request body
    var make = requestBody.make;
    var model = requestBody.model;
    var year = requestBody.year;
    var country = requestBody.country;
    var city = requestBody.city;

    // 5. Generate an error message and a 404 if no vin is provided
    if (!vin || vin === 'undefined' || vin === 'null') {
        response.setStatus(404);
        response.setBody({
            error: {
                message: 'VIN parameter is required',
                detail: 'Please provide a VIN in the request path'
            }
        });
        return;
    }

    // 6. Generate an error message and a 404 if the request body contains none of the accepted data
    if (!make && !model && !year && !country && !city) {
        response.setStatus(404);
        response.setBody({
            error: {
                message: 'Request body data is required',
                detail: 'Please provide at least one field to update: make, model, year, country, or city'
            }
        });
        return;
    }

    // 7. Perform a GlideRecord query of the x_snc_vehicle_ma_0_vehicle table using the vin
    var vehicleGR = new GlideRecord('x_snc_vehicle_ma_0_vehicle');
    vehicleGR.addQuery('vin', vin);
    vehicleGR.query();

    // 8. Generate an error message and a 404 if no vehicle is found
    if (!vehicleGR.next()) {
        response.setStatus(404);
        response.setBody({
            error: {
                message: 'Vehicle not found',
                detail: 'No vehicle found with VIN: ' + vin
            }
        });
        return;
    }

    // 9. If a vehicle record is found, update it using the variables from Step 4
    if (make) {
        vehicleGR.setValue('make', make);
    }
    if (model) {
        vehicleGR.setValue('model', model);
    }
    if (year) {
        vehicleGR.setValue('year', year);
    }
    if (country) {
        vehicleGR.setValue('country', country);
    }
    if (city) {
        vehicleGR.setValue('city', city);
    }

    vehicleGR.update();

    // 10. If the update was successful: set status to 200 and create response object
    response.setStatus(200);

    var vehicleObj = {
        make: vehicleGR.getValue('make'),
        model: vehicleGR.getValue('model'),
        vin: vehicleGR.getValue('vin'),
        year: vehicleGR.getValue('year'),
        country: vehicleGR.getValue('country'),
        city: vehicleGR.getValue('city'),
        sys_id: vehicleGR.getUniqueValue()
    };

    answer.push(vehicleObj);

    response.setBody({
        answer: answer
    });

})(request, response);
